import json, sys
baseline = json.load(open('baseline-packages.json'))
after = json.load(sys.stdin)

def extract(data):
    pkgs = {}
    for proj in data['projects']:
        pname = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for p in fw['topLevelPackages']:
                pkgs[(pname, p['id'])] = p['resolvedVersion']
    return pkgs

b = extract(baseline)
a = extract(after)
if b == a:
    print('All packages resolve identically. Conversion is version-neutral.')
else:
    for k in sorted(set(list(b.keys()) + list(a.keys()))):
        bv = b.get(k, 'MISSING')
        av = a.get(k, 'MISSING')
        if bv != av:
            print(f'CHANGED: {k[0]} {k[1]}: {bv} -> {av}')
" 2>&1 && dotnet package list --format json 2>/dev/null > after-cpm-packages.json

